package cz.zamboch.distilled;

import cz.zamboch.autopilot.core.ml.GbmTreeEnsemble;

/**
 * Auto-generated model data for the fire_timing GBM model.
 * Tree data is embedded as Base64-encoded string constants — no file I/O,
 * works inside Robocode's security sandbox.
 *
 * <p>Model: 200 trees, 22,024 total nodes, 1 class(es),
 * 81 input features. Base score: 0.5.</p>
 */
public final class FireTimingData {

    private FireTimingData() {}

    /** Feature column names in model input order. */
    public static final String[] FEATURE_NAMES = {
        "opponent_energy", "our_gun_heat", "ticks_since_scan", "cumulative_damage_dealt", "cumulative_damage_received", "cumulative_our_hit_rate", "cumulative_opponent_hit_rate", "cumulative_our_shots_fired", "cumulative_opponent_shots_detected", "opponent_center_distance", "opponent_corner_proximity", "distance", "bearing_to_opponent_abs", "opponent_dist_to_wall_min", "our_x", "our_y", "our_heading", "our_velocity", "opponent_x", "opponent_y", "opponent_heading", "opponent_wall_ahead_distance", "opponent_velocity", "opponent_lateral_velocity", "opponent_advancing_velocity", "opponent_heading_delta", "energy_ratio", "our_lateral_velocity", "our_dist_to_wall_min", "our_bullet_speed", "our_bullet_travel_time", "mea_for_our_bullet", "ticks_since_we_fired", "n_our_waves_in_flight", "nearest_our_wave_gap", "envelope_fill_ratio", "reachable_distance_min", "reachable_distance_max", "reachable_gf_range", "opponent_lateral_direction", "opponent_velocity_delta", "opponent_is_decelerating", "opponent_time_since_direction_change", "opponent_angular_velocity", "opponent_max_turn_rate", "distance_norm", "linear_target_angle", "linear_target_offset", "circular_target_angle", "circular_target_offset", "gf_bearing_offset", "gf_current_at_power_1", "gf_current_at_power_1_5", "gf_current_at_power_2", "opponent_guess_factor", "opponent_avg_lateral_velocity_10", "opponent_avg_lateral_velocity_30", "opponent_heading_delta_variability_10", "opponent_velocity_variability_10", "opponent_time_since_velocity_change", "opponent_distance_since_direction_change", "distance_wmean", "distance_wstd", "bearing_to_opponent_abs_wmean", "bearing_to_opponent_abs_wstd", "opponent_dist_to_wall_min_wmean", "opponent_dist_to_wall_min_wstd", "our_gun_heat_wmean", "our_gun_heat_wstd", "ticks_since_scan_wmean", "ticks_since_scan_wstd", "opponent_energy_wmean", "opponent_energy_wstd", "our_x_wmean", "our_x_wstd", "our_y_wmean", "our_y_wstd", "our_heading_wmean", "our_heading_wstd", "our_velocity_wmean", "our_velocity_wstd"
    };

    public static final int N_TREES = 200;
    public static final double BASE_SCORE = 0.5;
    public static final int N_CLASSES = 1;

    // Base64-encoded tree data (split to stay under 64KB per string constant)
    private static final String D0 = "";
    private static final String D1 = "";
    private static final String D2 = "";
    private static final String D3 = "";
    private static final String D4 = "";
    private static final String D5 = "";
    private static final String D6 = "";

    /**
     * Decode and load the tree ensemble from embedded Base64 data.
     * Called once at robot startup. No file I/O.
     */
    public static GbmTreeEnsemble load() {
        try {
            StringBuilder sb = new StringBuilder(411664);
            sb.append(D0);
            sb.append(D1);
            sb.append(D2);
            sb.append(D3);
            sb.append(D4);
            sb.append(D5);
            sb.append(D6);
            byte[] raw = java.util.Base64.getDecoder().decode(sb.toString());
            java.nio.ByteBuffer bb = java.nio.ByteBuffer.wrap(raw);

            int nTrees = bb.getInt();
            double baseScore = bb.getFloat();
            int nClasses = bb.getShort();

            int[] offsets = new int[nTrees];
            int totalNodes = 0;

            int[] featureIndex;
            double[] threshold;
            int[] leftChild;
            int[] rightChild;
            double[] leafValue;

            // First pass: compute total nodes
            int pos = bb.position();
            for (int t = 0; t < nTrees; t++) {
                int n = bb.getShort();
                totalNodes += n;
                bb.position(bb.position() + n * 14); // skip: 2+4+2+2+4 bytes per node
            }

            // Allocate flat arrays
            featureIndex = new int[totalNodes];
            threshold = new double[totalNodes];
            leftChild = new int[totalNodes];
            rightChild = new int[totalNodes];
            leafValue = new double[totalNodes];

            // Second pass: read data
            bb.position(pos);
            int offset = 0;
            for (int t = 0; t < nTrees; t++) {
                int n = bb.getShort();
                offsets[t] = offset;
                for (int i = 0; i < n; i++) featureIndex[offset + i] = bb.getShort();
                for (int i = 0; i < n; i++) threshold[offset + i] = bb.getFloat();
                for (int i = 0; i < n; i++) leftChild[offset + i] = bb.getShort();
                for (int i = 0; i < n; i++) rightChild[offset + i] = bb.getShort();
                for (int i = 0; i < n; i++) leafValue[offset + i] = bb.getFloat();
                offset += n;
            }

            return new GbmTreeEnsemble(nTrees, offsets,
                    featureIndex, threshold, leftChild, rightChild,
                    leafValue, baseScore, nClasses);
        } catch (Exception e) {
            throw new RuntimeException("Failed to decode fire_timing model", e);
        }
    }
}
